const o={threshold:.1},r=new IntersectionObserver(e=>{e.forEach(s=>{s.isIntersecting&&s.target.classList.add("active")})},o);document.querySelectorAll(".reveal").forEach(e=>r.observe(e));const c=document.getElementById("navbar"),t=document.getElementById("hamburger"),n=document.getElementById("navLinks");window.addEventListener("scroll",()=>{c?.classList.toggle("scrolled",window.scrollY>20)});t?.addEventListener("click",()=>{n?.classList.toggle("open"),t?.classList.toggle("open")});document.querySelectorAll(".nav-link").forEach(e=>{e.addEventListener("click",()=>{n?.classList.remove("open"),t?.classList.remove("open")})});
